import { useEffect, useState } from "react";

function App() {
  const [energy, setEnergy] = useState(null);

  useEffect(() => {
    fetch("http://localhost:5000/energy")
      .then((res) => res.json())
      .then((data) => setEnergy(data));
  }, []);

  return (
    <div style={{ padding: "20px", fontFamily: "Arial" }}>
      <h1>OpenGreenGrid Dashboard</h1>

      {energy ? (
        <div>
          <h2>Generated Power: {energy.generatedPower} kWh</h2>
          <h2>Consumed Power: {energy.consumedPower} kWh</h2>
          <h2>Battery Level: {energy.batteryLevel}%</h2>
        </div>
      ) : (
        <h2>Loading energy data...</h2>
      )}
    </div>
  );
}

export default App;
